async function createDeleteStoryRequest(story_id) {
	try {
		return await fetch(`/api/stories/${story_id}/delete`, { method: "DELETE" });
	} catch (error) {
		return { responseErr: "Server error. Please try again later" + error.toString() };
	}
}
async function createUpdateStoryRequest(story_title, story_id) {
	try {
		return await fetch(`/api/stories/${story_id}/update`, {
			method: "PATCH",
			body: JSON.stringify({ story_title }),
			headers: new Headers({ "Content-Type": "application/json" })
		});
	} catch (error) {
		return { responseErr: "Server error. Please try again later" + error.toString() };
	}
}
